1270:                                         NSSSocketControl* infoObject,
1271:                                         const char* host, bool haveHTTPSProxy) {
1272:   // Memory allocated here is released when fd is closed, regardless of the
1273:   // success of this function.
1274:   PRFileDesc* sslSock = SSL_ImportFD(nullptr, fd);
1275:   if (!sslSock) {
1276:     return nullptr;
