1278:   if (SSL_HandshakeCallback(sslSock, HandshakeCallback, infoObject) !=
1279:       SECSuccess) {
1280:     return nullptr;
1281:   }
1282:   if (SSL_SecretCallback(sslSock, SecretCallback, infoObject) != SECSuccess) {
1283:     return nullptr;
1284:   }
1285:   if (SSL_SetCanFalseStartCallback(sslSock, CanFalseStartCallback,
1286:                                    infoObject) != SECSuccess) {
1287:     return nullptr;
1288:   }
1289: 
1290:   // Disable this hook if we connect anonymously. See bug 466080.
1291:   uint32_t flags = infoObject->GetProviderFlags();
1292:   SSLGetClientAuthData clientAuthDataHook = SSLGetClientAuthDataHook;
1293:   // Provide the client cert to HTTPS proxy no matter if it is anonymous.
1294:   if (flags & nsISocketProvider::ANONYMOUS_CONNECT && !haveHTTPSProxy &&
1295:       !(flags & nsISocketProvider::ANONYMOUS_CONNECT_ALLOW_CLIENT_CERT)) {
1296:     clientAuthDataHook = nullptr;
1297:   }
1298:   if (SSL_GetClientAuthDataHook(sslSock, clientAuthDataHook, infoObject) !=
1299:       SECSuccess) {
1300:     return nullptr;
1301:   }
